/* eslint-disable no-restricted-globals */
import { useState, useEffect, useRef } from "react";

const ADMIN_PASSWORD = "ncc@admin2024";

const defaultData = {
  stats: { visitors: 5507184, activeCadets: 221464, registeredCadets: 365094 },
  nccLogo: "",
  thaparLogo: "",
  backLink: "https://www.thapar.edu/students",
  heroImage: "https://upload.wikimedia.org/wikipedia/commons/thumb/4/4b/NCC_parade.jpg/1200px-NCC_parade.jpg",
  aim: {
    title: "Aim Of the NCC Digital Forum",
    desc1: "NCC Digital Forum is a platform for Cadets to share their experiences and values imbibed while undergoing NCC Training. The 'Cadet's Corner' would enrich the viewers with systematically archived experiences of NCC cadets in text, audio and video formats.",
    desc2: "The forum provides for an unprecedented exchange of experiences amongst 15 Lac NCC Cadets across the country thereby contributing towards National Integration and Nation Building."
  },
  news: [
    { id: 1, title: "Republic Day Parade 2024", desc: "NCC cadets from across India participated in the Republic Day Parade held at Kartavya Path, New Delhi.", date: "26 Jan 2024" },
    { id: 2, title: "Annual Training Camp", desc: "Annual training camp scheduled for selected NCC cadets from all wings during March 2024.", date: "15 Mar 2024" },
    { id: 3, title: "Best Cadet Award", desc: "PM's Rally Best Cadet Award ceremony announced. Nominations open for all senior division cadets.", date: "05 Feb 2024" }
  ],
  events: [
    { id: 1, title: "Youth Exchange Programme", desc: "YEP delegation to visit Japan and South Korea. Applications invited from A-cert cadets.", date: "20 Apr 2024", image: "" },
    { id: 2, title: "National Integration Camp", desc: "NIC to be held at Delhi from 1-15 April 2024. All states to nominate cadets.", date: "01 Apr 2024", image: "" }
  ],
  categories: [
    { id: 1, name: "Training", cover: "https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400" },
    { id: 2, name: "Social Activity", cover: "https://images.unsplash.com/photo-1529156069898-49953e39b3ac?w=400" },
    { id: 3, name: "Misc", cover: "https://images.unsplash.com/photo-1544197150-b99a580bb7a8?w=400" },
    { id: 4, name: "Sports & Adventures", cover: "https://images.unsplash.com/photo-1551698618-1dfe5d97d256?w=400" }
  ],
  albums: [
    { id: 1, catId: 1, title: "Basic Training 2024", desc: "Drill and parade training sessions.", images: ["https://images.unsplash.com/photo-1531266752426-aad472b7bbf4?w=400"] },
    { id: 2, catId: 2, title: "Blood Donation Camp", desc: "Social awareness blood donation drive.", images: ["https://images.unsplash.com/photo-1491438590914-bc09fcaaf77a?w=400"] },
    { id: 3, catId: 4, title: "Trekking Expedition", desc: "Mountain trekking and adventure camp.", images: ["https://images.unsplash.com/photo-1551632811-561732d1e306?w=400"] }
  ],
  alumni: [
    { id: 1, name: "Col. Rajesh Kumar (Retd.)", desc: "Served as NCC Officer for 25 years. Currently working in defence education sector.", image: "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=200" },
    { id: 2, name: "Dr. Priya Sharma", desc: "NCC cadet from 2005-2009. Now a renowned social worker and IAS officer.", image: "https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=200" }
  ],
  archives: [
    { id: 1, heading: "NCC Foundation Day 1948", desc: "Historical photographs and documents from the founding of NCC on 16 April 1948.", image: "https://images.unsplash.com/photo-1568605114967-8130f3a36994?w=400" },
    { id: 2, heading: "Silver Jubilee Celebrations", desc: "25 years celebration of NCC with special parades and events across the nation.", image: "https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=400" }
  ],
  registrations: []
};

// ✅ REPLACE WITH THIS (MongoDB API version):
const API = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

async function loadData() {
  try {
    const res = await fetch(`${API}/content/all`);
    const json = await res.json();
    return json || defaultData;
  } catch {
    return defaultData;
  }
}

async function saveData(key, value) {
  try {
    await fetch(`${API}/content/update`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ key, value })
    });
  } catch (err) {
    console.error('Save failed:', err);
  }
}

// ─── ICONS ───────────────────────────────────────────────────────────────────
const Icon = ({ name, size = 16, color = "currentColor" }) => {
  const icons = {
    edit: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>,
    trash: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/></svg>,
    plus: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>,
    close: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>,
    search: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>,
    eye: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>,
    save: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg>,
    logout: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>,
    img: <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>,
  };
  return icons[name] || null;
};

// ─── MODAL ────────────────────────────────────────────────────────────────────
function Modal({ title, onClose, children, wide }) {
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: "1rem" }}>
      <div style={{ background: "#fff", borderRadius: 16, width: wide ? 700 : 480, maxWidth: "100%", maxHeight: "90vh", overflow: "auto", boxShadow: "0 20px 60px rgba(0,0,0,0.3)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "1.2rem 1.5rem", borderBottom: "1px solid #eee" }}>
          <h3 style={{ margin: 0, fontSize: 18, fontWeight: 700, color: "#1a1a2e" }}>{title}</h3>
          <button onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer", padding: 4, borderRadius: 8, color: "#666" }}><Icon name="close" size={20} /></button>
        </div>
        <div style={{ padding: "1.5rem" }}>{children}</div>
      </div>
    </div>
  );
}

// ─── FORM INPUTS ─────────────────────────────────────────────────────────────
const inp = { width: "100%", padding: "10px 12px", border: "1.5px solid #ddd", borderRadius: 8, fontSize: 14, marginBottom: 10, boxSizing: "border-box", fontFamily: "inherit" };
const btn = (bg, color = "#fff") => ({ background: bg, color, border: "none", borderRadius: 8, padding: "10px 18px", cursor: "pointer", fontSize: 14, fontWeight: 600 });

function Field({ label, value, onChange, type = "text", rows }) {
  return (
    <div style={{ marginBottom: 12 }}>
      <label style={{ fontSize: 12, fontWeight: 600, color: "#555", display: "block", marginBottom: 4 }}>{label}</label>
      {rows
        ? <textarea value={value} onChange={e => onChange(e.target.value)} rows={rows} style={{ ...inp, resize: "vertical" }} />
        : <input type={type} value={value} onChange={e => onChange(e.target.value)} style={inp} />}
    </div>
  );
}

// ─── EDIT OVERLAY BUTTON ─────────────────────────────────────────────────────
function EditBtn({ onClick, label = "Edit" }) {
  return (
    <button onClick={onClick} style={{ position: "absolute", top: 8, right: 8, background: "#1a73e8", color: "#fff", border: "none", borderRadius: 20, padding: "4px 10px", fontSize: 11, fontWeight: 700, cursor: "pointer", zIndex: 10, display: "flex", alignItems: "center", gap: 4 }}>
      <Icon name="edit" size={11} color="#fff" /> {label}
    </button>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// MAIN APP
// ═══════════════════════════════════════════════════════════════════════════════
export default function App() {
  const [data, setData] = useState(loadData);
  const [isAdmin, setIsAdmin] = useState(false);
  const [view, setView] = useState("home"); // home | admin | category | alumni | archives
  const [viewParam, setViewParam] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");

  useEffect(() => { saveData(data); }, [data]);

  // ─── VISITOR INCREMENT ────────────────────────────────────────────────────
  useEffect(() => {
    setData(d => ({ ...d, stats: { ...d.stats, visitors: d.stats.visitors + 1 } }));
  }, []);

  const update = (key, val) => setData(d => ({ ...d, [key]: val }));

  if (view === "admin") return <AdminPanel data={data} update={update} setData={setData} onLogout={() => { setIsAdmin(false); setView("home"); }} />;
  if (view === "login") return <LoginPage onLogin={() => { setIsAdmin(true); setView("admin"); }} onBack={() => setView("home")} />;
  if (view === "category") return <CategoryPage catId={viewParam} data={data} onBack={() => setView("home")} isAdmin={isAdmin} update={update} setData={setData} />;
  if (view === "alumni") return <AlumniPage data={data} onBack={() => setView("home")} isAdmin={isAdmin} update={update} />;
  if (view === "archives") return <ArchivesPage data={data} onBack={() => setView("home")} isAdmin={isAdmin} update={update} />;

  return (
    <MainPage
      data={data} update={update} setData={setData}
      isAdmin={isAdmin}
      onAdminLogin={() => setView("login")}
      onCategoryClick={id => { setViewParam(id); setView("category"); }}
      onAlumni={() => setView("alumni")}
      onArchives={() => setView("archives")}
      searchQuery={searchQuery} setSearchQuery={setSearchQuery}
    />
  );
}

