          {tabs.map(t => (
            <button key={t} onClick={() => setTab(t)} style={{ display: "block", width: "100%", padding: "12px 20px", background: tab === t ? "#e8f0fe" : "none", border: "none", cursor: "pointer", textAlign: "left", fontSize: 13, fontWeight: tab === t ? 700 : 400, color: tab === t ? "#1a73e8" : "#555", borderLeft: tab === t ? "3px solid #1a73e8" : "3px solid transparent", textTransform: "capitalize" }}>
              {t === "overview" ? "📊 Overview" : t === "stats" ? "📈 Stats" : t === "news" ? "📰 News" : t === "events" ? "📅 Events" : t === "categories" ? "🎖️ Categories" : t === "alumni" ? "🎓 Alumni" : t === "archives" ? "🏛️ Archives" : "📝 Registrations"}
            </button>
          ))}
        </div>

        {/* Content */}
        <div style={{ flex: 1, padding: "30px", overflow: "auto" }}>
          {tab === "overview" && <AdminOverview data={data} />}
          {tab === "stats" && <AdminStats data={data} update={update} />}
          {tab === "news" && <AdminNews data={data} update={update} />}
          {tab === "events" && <AdminEvents data={data} update={update} />}
          {tab === "categories" && <AdminCategories data={data} update={update} />}
          {tab === "alumni" && <AdminAlumni data={data} update={update} />}
          {tab === "archives" && <AdminArchives data={data} update={update} />}
          {tab === "registrations" && <AdminRegistrations data={data} />}
        </div>
      </div>
    </div>
  );
}

