function AdminCategories({ data, update }) {
  const [showAddCat, setShowAddCat] = useState(false);
  const [catForm, setCatForm] = useState({ name: "", cover: "" });
  const [expandedCat, setExpandedCat] = useState(null);
  const [albumForms, setAlbumForms] = useState({});
  const [showAlbumAdd, setShowAlbumAdd] = useState({});
  const [picForms, setPicForms] = useState({});

  const addCat = () => {
    if (!catForm.name) return;
    update("categories", [...data.categories, { id: Date.now(), name: catForm.name, cover: catForm.cover }]);
    setCatForm({ name: "", cover: "" });
    setShowAddCat(false);
  };

  const addAlbum = (catId) => {
    const f = albumForms[catId] || { title: "", desc: "", images: "" };
    if (!f.title) return;
    const imgs = f.images.split("\n").filter(Boolean);
    update("albums", [...data.albums, { id: Date.now(), catId, title: f.title, desc: f.desc, images: imgs }]);
    setAlbumForms(prev => ({ ...prev, [catId]: { title: "", desc: "", images: "" } }));
    setShowAlbumAdd(prev => ({ ...prev, [catId]: false }));
  };

  const addPicToAlbum = (albumId) => {
    const url = picForms[albumId] || "";
    if (!url.trim()) return;
    update("albums", data.albums.map(a => a.id === albumId ? { ...a, images: [...a.images, url.trim()] } : a));
    setPicForms(prev => ({ ...prev, [albumId]: "" }));
  };

  const removePic = (albumId, idx) => {
    update("albums", data.albums.map(a => a.id === albumId ? { ...a, images: a.images.filter((_, i) => i !== idx) } : a));
  };

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
        <h2 style={{ color: "#1a1a6e", margin: 0 }}>🎖️ Categories & Albums</h2>
        <button onClick={() => setShowAddCat(s => !s)} style={{ ...btn("#1a73e8"), borderRadius: 20, display: "flex", alignItems: "center", gap: 6 }}>
          <Icon name="plus" size={14} color="#fff" /> Add Category
        </button>
      </div>

      {/* Add Category Form */}
      {showAddCat && (
        <AdminCard title="New Category">
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
            <Field label="Category Name" value={catForm.name} onChange={v => setCatForm(f => ({ ...f, name: v }))} />
            <Field label="Cover Image URL" value={catForm.cover} onChange={v => setCatForm(f => ({ ...f, cover: v }))} />
          </div>
          {catForm.cover && <img src={catForm.cover} alt="preview" style={{ width: "100%", height: 120, objectFit: "cover", borderRadius: 8, marginBottom: 12 }} onError={e => e.target.style.display="none"} />}
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={addCat} style={btn("#0f9d58")}>✅ Create Category</button>
            <button onClick={() => setShowAddCat(false)} style={btn("#eee", "#333")}>Cancel</button>
          </div>
        </AdminCard>
      )}

      {/* Category List */}
      {data.categories.map(cat => {
        const albums = data.albums.filter(a => a.catId === cat.id);
        const isExpanded = expandedCat === cat.id;
        const af = albumForms[cat.id] || { title: "", desc: "", images: "" };

        return (
          <div key={cat.id} style={{ background: "#fff", borderRadius: 14, marginBottom: 16, border: "1px solid #e8eaed", overflow: "hidden" }}>
            {/* Category Header */}
            <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 20px", background: "#f8faff", borderBottom: isExpanded ? "1px solid #e3eaff" : "none" }}>
              <img src={cat.cover || "https://placehold.co/60/1a1a6e/white?text=C"} alt={cat.name} style={{ width: 52, height: 52, objectFit: "cover", borderRadius: 8 }} onError={e => e.target.src="https://placehold.co/60/1a1a6e/white?text=C"} />
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, color: "#1a1a6e", fontSize: 16 }}>{cat.name}</div>
                <div style={{ color: "#888", fontSize: 12 }}>{albums.length} album(s) · {albums.reduce((s,a)=>s+a.images.length,0)} photo(s)</div>
              </div>
              <div style={{ display: "flex", gap: 8 }}>
                <button onClick={() => setExpandedCat(isExpanded ? null : cat.id)} style={{ ...btn(isExpanded ? "#1a1a6e" : "#e8f0fe", isExpanded ? "#fff" : "#1a73e8"), fontSize: 12, borderRadius: 8 }}>
                  {isExpanded ? "▲ Collapse" : "▼ Manage"}
                </button>
                <button onClick={() => { const ok = window.confirm(`Delete category "${cat.name}" and all its albums?`); if(ok) { update("categories", data.categories.filter(c=>c.id!==cat.id)); update("albums", data.albums.filter(a=>a.catId!==cat.id)); }}} style={{ ...btn("#fce8e6", "#c5221f"), fontSize: 12, borderRadius: 8 }}>🗑️</button>
              </div>
            </div>

            {/* Expanded: Albums & Pictures */}
            {isExpanded && (
              <div style={{ padding: 20 }}>
                {/* Add Album Button */}
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
                  <div style={{ fontWeight: 700, color: "#555", fontSize: 14 }}>Albums in {cat.name}</div>
                  <button onClick={() => setShowAlbumAdd(prev => ({ ...prev, [cat.id]: !prev[cat.id] }))} style={{ ...btn("#e8f0fe", "#1a73e8"), fontSize: 12, borderRadius: 20, display: "flex", alignItems: "center", gap: 5 }}>
                    <Icon name="plus" size={12} color="#1a73e8" /> Add Album
                  </button>
                </div>

                {/* Add Album Form */}
                {showAlbumAdd[cat.id] && (
                  <div style={{ background: "#f0f4ff", borderRadius: 10, padding: 14, marginBottom: 16, border: "1.5px solid #b3c6ff" }}>
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                      <Field label="Album Title" value={af.title} onChange={v => setAlbumForms(p=>({...p,[cat.id]:{...af,title:v}}))} />
                      <Field label="Description" value={af.desc} onChange={v => setAlbumForms(p=>({...p,[cat.id]:{...af,desc:v}}))} />
                    </div>
                    <label style={{ fontSize: 12, fontWeight: 600, color: "#555", display: "block", marginBottom: 4 }}>Image URLs (one per line)</label>
                    <textarea value={af.images} onChange={e => setAlbumForms(p=>({...p,[cat.id]:{...af,images:e.target.value}}))} rows={3} style={{ ...inp, resize: "vertical" }} placeholder="https://example.com/photo.jpg" />
                    <div style={{ display: "flex", gap: 8 }}>
                      <button onClick={() => addAlbum(cat.id)} style={btn("#0f9d58")}>✅ Create Album</button>
                      <button onClick={() => setShowAlbumAdd(p=>({...p,[cat.id]:false}))} style={btn("#eee","#333")}>Cancel</button>
                    </div>
                  </div>
                )}

                {/* Albums List */}
                {albums.length === 0 && <p style={{ color: "#bbb", fontSize: 13 }}>No albums yet. Add one above.</p>}
                {albums.map(album => (
                  <div key={album.id} style={{ background: "#f8f9fa", borderRadius: 10, padding: 14, marginBottom: 12, border: "1px solid #e8eaed" }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
                      <div>
                        <div style={{ fontWeight: 700, color: "#1a1a6e", fontSize: 14 }}>{album.title}</div>
                        <div style={{ color: "#888", fontSize: 12 }}>{album.desc} · {album.images.length} photo(s)</div>
                      </div>
                      <button onClick={() => update("albums", data.albums.filter(a=>a.id!==album.id))} style={{ ...btn("#fce8e6","#c5221f"), fontSize: 11, borderRadius: 6, padding:"5px 10px" }}>🗑️ Delete Album</button>
                    </div>

                    {/* Photo grid */}
                    <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 10 }}>
                      {album.images.map((img, idx) => (
                        <div key={idx} style={{ position: "relative", width: 80, height: 70 }}>
                          <img src={img} alt={`pic ${idx+1}`} style={{ width: 80, height: 70, objectFit: "cover", borderRadius: 6 }} onError={e => e.target.src="https://placehold.co/80x70/ccc/555?text=?"} />
                          <button onClick={() => removePic(album.id, idx)} style={{ position: "absolute", top: 2, right: 2, background: "rgba(200,0,0,0.85)", border: "none", borderRadius: "50%", width: 18, height: 18, cursor: "pointer", color: "#fff", fontSize: 11, display: "flex", alignItems: "center", justifyContent: "center", padding: 0 }}>×</button>
                        </div>
                      ))}
                    </div>

                    {/* Add picture to album */}
                    <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                      <input value={picForms[album.id] || ""} onChange={e => setPicForms(p=>({...p,[album.id]:e.target.value}))} placeholder="Paste image URL to add photo..." style={{ ...inp, margin: 0, flex: 1 }} />
                      <button onClick={() => addPicToAlbum(album.id)} style={{ ...btn("#1a73e8"), whiteSpace: "nowrap", padding: "10px 14px" }}>
                        <Icon name="plus" size={14} color="#fff" />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      })}
      {data.categories.length === 0 && <p style={{ color: "#aaa" }}>No categories yet. Create one above!</p>}
    </div>
  );
}

